import React from 'react';
import Navbar from '../src/components/pages/Navbar';
import Hero from '../src/components/pages/Hero';
import Collection from '../src/components/pages/Collection';
import Features from '../src/components/pages/Features';
import './App.css';

function App() {
  return (
    <div className="App" style={{ backgroundColor: '#FFF8E7', minHeight: '100vh', margin: 0, padding: 0 }}>
      <Navbar />
      <main>
        <Hero />
        <Collection />
        <Features />
      </main>
    </div>
  );
}

export default App;
